// ══════════════════════════════════════════════════════════════
// matchTopicExt2 — routes fallback lessons to new specific topics
// ══════════════════════════════════════════════════════════════

function matchTopicExt2(title, moduleSlug) {
  const t = normalize(title);
  const s = moduleSlug;

  // ── C# ─────────────────────────────────────────────────────
  if (s === "csharp") {
    // Skip lessons already handled well by seed-v2.js
    if (t.includes("linq") || t.includes("lambda")) return null;
    if (t.includes("async") || t.includes("await") || (t.includes("task") && !t.includes("management")) || t.includes("grpc") || t.includes("signalr")) return null;
    if (t.includes("modern") || t.includes("pattern matching") || t.includes("blazor") || t.includes("nullable")) return null;
    if (t.includes("mostenire") || t.includes("interfata") || t.includes("abstract") || t.includes("polimorfism")) return null;
    if (t.includes("clase") || t.includes("obiecte") || (t.includes("oop") && !t.includes("bune"))) return null;
    if (t.includes("colectii") || t.includes("collection") || t.includes("dictionary") || t.includes("generic")) return null;
    if (t.includes("record") && !t.includes("asp")) return null;

    // Route fallback lessons to specific topics
    if (t.includes("introducere") || t.includes("input") || t.includes("convers") || t.includes("conditii") || t.includes("bucle") || t.includes("metode") || t.includes("static") || t.includes("recursivitate") || t.includes("params") || t.includes("ref ")) return TOPICS["csharp::control-flow-cs"];
    if (t.includes("fisier") || t.includes("json") || t.includes("serializare") || t.includes("system.io")) return TOPICS["csharp::files-json-cs"];
    if (t.includes("delegates") || t.includes("events") || t.includes("eveniment") || t.includes("func<")) return TOPICS["csharp::delegates-events-cs"];
    if (t.includes("entity") || t.includes("ef core") || t.includes("dbcontext") || t.includes("orm") || (t.includes("framework") && t.includes("core"))) return TOPICS["csharp::ef-core-cs"];
    if (t.includes("dependency injection") || t.includes(" di ") || t.includes("ioc") || (t.includes("inject") && !t.includes("sql")) || t.includes("design pattern") || t.includes("solid") || t.includes("bune practici") || t.includes("pattern")) return TOPICS["csharp::di-patterns-cs"];
    if (t.includes("test") || t.includes("xunit") || t.includes("moq") || t.includes("unit testing")) return TOPICS["csharp::testing-patterns-cs"];
    if (t.includes("asp.net") || t.includes("aspnet") || t.includes("web api") || t.includes("controller") || t.includes("identity") || t.includes("jwt") || t.includes("rest api") || t.includes("project") || t.includes("proiect") || t.includes("mini proiect")) return TOPICS["csharp::aspnet-cs"];
    return null;
  }

  // ── PHP ─────────────────────────────────────────────────────
  if (s === "php") {
    // Skip lessons already handled well by seed-v2.js
    if (t.includes("oop") || (t.includes("clase") && t.includes("obiecte")) || t.includes("mostenire") || t.includes("trait") || t.includes("eloquent") || t.includes("design pattern")) return null;
    if (t.includes("pdo") || t.includes("mysql") || (t.includes("baza de date") && !t.includes("accesare"))) return null;
    if (t.includes("sesiune") || t.includes("cookie") || t.includes("autentificare") || t.includes("oauth")) return null;

    // Override wrong mapping (strings → php::arrays) + handle new fallback lessons
    if (t.includes("string") || t.includes("sir de") || t.includes("regex") || t.includes("expresii regulate") || t.includes("text ") || t.includes("caractere")) return TOPICS["php::strings-regex"];
    if (t.includes("variabil") || t.includes("operatori") || t.includes("tipuri de date") || t.includes("introducere")) return TOPICS["php::variables-intro"];
    if (t.includes("conditii") || t.includes("bucle") || t.includes("foreach") || t.includes("for,") || t.includes("while") || t.includes("switch") || t.includes("match expression") || t.includes("control")) return TOPICS["php::control-loops"];
    if (t.includes("functii") || t.includes("closures") || t.includes("closure") || t.includes("arrow function") || t.includes("function")) return TOPICS["php::functions-closures"];
    if (t.includes("fisier") || t.includes("exceptii") || t.includes("gestionare") || t.includes("erori") || t.includes("try") || t.includes("throw")) return TOPICS["php::exceptions-files"];
    if (t.includes("modern") || t.includes("php 8") || t.includes("php8") || t.includes("named") || t.includes("readonly") || t.includes("enum") || t.includes("fiber")) return TOPICS["php::modern-php8"];
    if (t.includes("cli") || t.includes("docker") || t.includes("performance") || t.includes("opcache") || t.includes("redis") || t.includes("queue") || t.includes("cron") || t.includes("websocket") || t.includes("deploy") || t.includes("containeriz")) return TOPICS["php::functions-closures"]; // CLI uses functions concepts
    if (t.includes("test") || t.includes("phpunit") || t.includes("securitate") || t.includes("owasp") || t.includes("best practices") || t.includes("security")) return TOPICS["php::exceptions-files"]; // security uses validation + exceptions
    if (t.includes("date") || t.includes("timp") || t.includes("datetime") || t.includes("email") || t.includes("phpmailer") || t.includes("smtp")) return TOPICS["php::strings-regex"]; // date/email use string manipulation
    return null;
  }

  // ── Tailwind ─────────────────────────────────────────────────
  if (s === "tailwind") {
    // Skip already-handled lessons
    if (t.includes("dark mode") || t.includes("darkmode") || t.includes("customizare") || t.includes("design system") || t.includes("theme") || t.includes("plugin") || t.includes("shadcn") || t.includes("v4")) return null;
    if (t.includes("hover") || t.includes("focus") && t.includes("group") || t.includes("peer") || (t.includes("animat") && !t.includes("avansat")) || t.includes("transition") || t.includes("stare")) return null;
    if (t.includes("grid") || (t.includes("flex") && !t.includes("avansat")) || t.includes("sidebar")) return null;
    if (t.includes("responsive") || t.includes("breakpoint") || t.includes("mobil") || t.includes("next.js")) return null;

    // Route fallback lessons
    if (t.includes("color") || t.includes("culori") || t.includes("background") || t.includes("fundal") || t.includes("tipograf") || t.includes("text") || t.includes("font") || t.includes("introducere") || t.includes("setup") || t.includes("instalare") || t.includes("utilities")) return TOPICS["tailwind::colors-typography"];
    if (t.includes("border") || t.includes("shadow") || t.includes("effect") || t.includes("glassmorphism") || t.includes("scroll") || t.includes("overflow") || t.includes("animati") || t.includes("avansat")) return TOPICS["tailwind::borders-shadows"];
    if (t.includes("spacing") || t.includes("sizing") || t.includes("form") || t.includes("formular") || t.includes("input")) return TOPICS["tailwind::spacing-forms"];
    if (t.includes("accessib") || t.includes("proiect") || t.includes("dashboard") || t.includes("landing") || t.includes("componente") || t.includes("saas") || t.includes("mini proiect") || t.includes("optimiz") || t.includes("performanta")) return TOPICS["tailwind::accessibility-projects"];
    return null;
  }

  return null;
}

// ══════════════════════════════════════════════════════════════
// MAIN
// ══════════════════════════════════════════════════════════════

const TARGET_MODULES = new Set(["csharp", "php", "tailwind"]);

const MODULE_LANG = {
  csharp: "csharp",
  php: "php",
  tailwind: "html",
};

const DIFF_ORDER = { easy: 0, medium: 1, hard: 2 };

async function main() {
  const modules = await p.module.findMany({
    where: { slug: { in: [...TARGET_MODULES] } },
    include: {
      lessons: { include: { tasks: true }, orderBy: { order: "asc" } },
    },
    orderBy: { order: "asc" },
  });

  let replaced = 0;
  let skipped = 0;

  for (const mod of modules) {
    console.log(`\nModul: ${mod.slug} (${mod.lessons.length} lecții)`);

    for (const lesson of mod.lessons) {
      const topic = matchTopicExt2(lesson.title, mod.slug);

      if (!topic) {
        skipped++;
        continue;
      }

      const currentFillblanks = lesson.tasks.filter((t) => t.type === "fillblank");
      const currentCodings = lesson.tasks.filter((t) => t.type === "coding");
      const quizTasks = lesson.tasks.filter((t) => t.type === "quiz");

      // Delete existing fillblank and coding tasks
      const idsToDelete = [...currentFillblanks, ...currentCodings].map((t) => t.id);
      if (idsToDelete.length > 0) {
        await p.task.deleteMany({ where: { id: { in: idsToDelete } } });
      }

      // Re-sort quiz tasks by difficulty
      const sortedQuiz = [...quizTasks].sort(
        (a, b) => (DIFF_ORDER[a.difficulty] ?? 1) - (DIFF_ORDER[b.difficulty] ?? 1)
      );
      for (let i = 0; i < sortedQuiz.length; i++) {
        await p.task.update({
          where: { id: sortedQuiz[i].id },
          data: { number: i + 1 },
        });
      }

      // Create 5 new fillblank tasks (positions 6-10)
      const fillblanks = topic.fillblanks.slice(0, 5);
      for (let i = 0; i < fillblanks.length; i++) {
        const fb = fillblanks[i];
        await p.task.create({
          data: {
            lessonId: lesson.id,
            type: "fillblank",
            number: 6 + i,
            difficulty: fb.difficulty,
            name: fb.name,
            question: fb.question,
            answer: fb.answer.toString().trim(),
            explanation: fb.explanation || null,
            options: [],
            language: MODULE_LANG[mod.slug] || "javascript",
          },
        });
      }

      // Create 5 new coding tasks (positions 11-15)
      const codings = topic.codings.slice(0, 5);
      for (let i = 0; i < codings.length; i++) {
        const cd = codings[i];
        await p.task.create({
          data: {
            lessonId: lesson.id,
            type: "coding",
            number: 11 + i,
            difficulty: cd.difficulty,
            name: cd.name,
            question: cd.question,
            answer: "",
            starterCode: cd.starterCode,
            expectedOutput: (cd.expectedOutput || "").trim(),
            options: [],
            language: cd.language || MODULE_LANG[mod.slug] || "javascript",
          },
        });
      }

      replaced += 10;
    }
  }

  console.log("\n==================================================");
  console.log(`Înlocuite: ${replaced} task-uri`);
  console.log(`Sărite:    ${skipped} lecții (deja cu content specific)`);
  console.log("==================================================");
}

main().catch(console.error).finally(() => p.$disconnect());
